const items = $input.all();
const results = [];
for (let i = 0; i < items.length; i++) {
  const aiResponse = items[i].json;
  let prev;
  try { prev = $('📍 Sacramento Suburb Data').all()[i].json; } catch(e) { prev = items[i].json; }
  let rawText = '';
  try { rawText = aiResponse.content[0].text; } catch(e) {
    results.push({ json: { error: 'Could not read AI response', suburb: prev.suburb || '' } });
    continue;
  }
  rawText = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  let pageData;
  try { pageData = JSON.parse(rawText); } catch(e) {
    const match = rawText.match(/\{[\s\S]*\}/);
    if (match) { try { pageData = JSON.parse(match[0]); } catch(e2) { results.push({ json: { error: 'Invalid JSON', suburb: prev.suburb || '' } }); continue; } }
    else { results.push({ json: { error: 'No JSON found', suburb: prev.suburb || '' } }); continue; }
  }
  const suburb = prev.suburb || '';
  const slugify = s => s.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  const slug = slugify(suburb) + '-dog-grooming';
  const faqItems = (pageData.faqs || []).map(f => ({ question: f.q, answer: f.a }));
  const bodyText = (pageData.sections || []).map(s => s.h2 + '\n\n' + s.body).join('\n\n');
  results.push({ json: {
    suburb, slug,
    title: pageData.h1 || ('Dog Grooming in ' + suburb + ', CA | The Rich Groomer'),
    intro: pageData.intro || '',
    bodyContent: bodyText,
    faqItems,
    metaTitle: 'Dog Grooming in ' + suburb + ', CA | The Rich Groomer',
    metaDescription: pageData.metaDescription || '',
    imagePrompt: prev.image_prompt || '',
    imageAlt: 'Dog grooming in ' + suburb + ' Sacramento - The Rich Groomer'
  }});
}
return results;

